import { useEffect, useState } from "react";
import { Link, NavLink, Routes, Route, useLocation } from "react-router-dom";
import { motion } from "motion/react";
import { Menu, X, Github } from "lucide-react";
import ModelExplorer from "./components/ModelExplorer";
import ModelDetail from "./components/ModelDetail";
import Manifesto from "./components/Manifesto";
import ResearchView from "./components/ResearchView";
import PapersView from "./components/PapersView";
import DocsView from "./components/DocsView";
import AboutView from "./components/AboutView";
import PaperDetail from "./components/PaperDetail";
import Home from "./components/Home";
import NotFound from "./components/NotFound";

const LOGO_LETTERS: { ch: string; keep: boolean }[] = [
  { ch: "H", keep: true },
  { ch: "E", keep: false },
  { ch: "L", keep: false },
  { ch: "I", keep: true },
  { ch: "O", keep: false },
  { ch: "S", keep: false },
];

const NAV_LINKS: { label: string; to: string }[] = [
  { label: "Home", to: "/" },
  { label: "Models", to: "/models" },
  { label: "Research", to: "/research" },
  { label: "Papers", to: "/papers" },
  { label: "Docs", to: "/docs" },
  { label: "About", to: "/about" },
];

function navClass({ isActive }: { isActive: boolean }): string {
  return `transition-all duration-200 cursor-pointer pb-1 border-b-2 ${
    isActive
      ? "text-black border-black"
      : "text-zinc-500 hover:text-black border-transparent"
  }`;
}

function ScrollToTop() {
  const { pathname } = useLocation();
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: "instant" });
  }, [pathname]);
  return null;
}

function Header({ scrolled }: { scrolled: boolean }) {
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  useEffect(() => {
    if (!isMobileMenuOpen) return;
    const close = () => setIsMobileMenuOpen(false);
    window.addEventListener("scroll", close, { passive: true });
    return () => window.removeEventListener("scroll", close);
  }, [isMobileMenuOpen]);

  return (
    <>
      <header id="main-header" className="max-w-7xl mx-auto w-full mt-4 px-6 md:px-12 py-5 flex items-center justify-between sticky top-4 rounded-2xl bg-[#FAF9F6]/80 backdrop-blur-md z-30 border border-zinc-200/50 shadow-[0_8px_30px_rgb(0,0,0,0.06)]">
        <div className="flex flex-col">
          <Link
            to="/"
            className="flex items-baseline font-serif font-bold text-3xl tracking-tight text-black select-none hover:opacity-80 transition-opacity cursor-pointer text-left"
          >
            {LOGO_LETTERS.map((l, i) => (
              <span
                key={i}
                className={`inline-block overflow-hidden whitespace-nowrap transition-all duration-300 ${
                  l.keep
                    ? "opacity-100 max-w-[1em]"
                    : scrolled
                      ? "opacity-0 max-w-0"
                      : "opacity-100 max-w-[1em]"
                }`}
              >
                {l.ch}
              </span>
            ))}
          </Link>
        </div>

        {/* Desktop Navigation Links */}
        <nav className="hidden md:flex items-center space-x-10 text-sm font-mono font-bold uppercase tracking-wider">
          {NAV_LINKS.map((link) => (
            <NavLink key={link.to} to={link.to} end={link.to === "/"} className={navClass}>
              {link.label}
            </NavLink>
          ))}
        </nav>

        {/* Mobile Menu Trigger */}
        <div className="md:hidden">
          <button
            onClick={() => setIsMobileMenuOpen(!isMobileMenuOpen)}
            className="p-2 text-zinc-600 hover:text-black focus:outline-none cursor-pointer"
            aria-label="Toggle navigation menu"
          >
            {isMobileMenuOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
          </button>
        </div>
      </header>

      {/* Mobile Navigation Dropdown Menu */}
      <motion.div
        initial={{ height: 0, opacity: 0 }}
        animate={{ height: isMobileMenuOpen ? "auto" : 0, opacity: isMobileMenuOpen ? 1 : 0 }}
        className="md:hidden overflow-hidden bg-[#FAF9F6] border-b border-zinc-200 border-x px-6 fixed w-full left-0 top-24 z-20 rounded-b-2xl"
      >
        <div className="flex flex-col space-y-4 py-6 pb-8 text-sm font-mono font-bold uppercase tracking-wider items-start">
          {NAV_LINKS.map((link) => (
            <NavLink
              key={link.to}
              to={link.to}
              end={link.to === "/"}
              onClick={() => setIsMobileMenuOpen(false)}
              className={({ isActive }) =>
                `text-left pb-0.5 border-b-2 ${
                  isActive
                    ? "text-black border-black"
                    : "text-zinc-500 hover:text-black border-transparent"
                }`
              }
            >
              {link.label}
            </NavLink>
          ))}
        </div>
      </motion.div>
    </>
  );
}

